item.command:
/bin/zsh -lc "node --input-type=module <<'NODE'
import { readFileSync } from 'node:fs';
const { rows } = JSON.parse(readFileSync('/tmp/balance-baseline.json','utf8'));
const types = new Map();
for (const row of rows) {
  for (const line of readFileSync(row.tracePath,'utf8').trim().split('\\n').slice(1)) {
    const turn = JSON.parse(line);
    for (const event of turn.events ?? []) types.set(event.type, (types.get(event.type) ?? 0)+1);
  }
}
for (const [type,count] of [...types].sort((a,b)=>b[1]-a[1])) console.log(type, count);
NODE"

