/bin/zsh -lc "node --input-type=module <<'NODE'
import { readFileSync } from 'node:fs';
const { rows } = JSON.parse(readFileSync('/tmp/balance-baseline.json','utf8'));
const bandForDepth = d => d <= 4 ? 'shallows' : d <= 9 ? 'middle' : 'lowest';
const byDepth = new Map();
const byBand = new Map();
const byAtk = new Map();
const deaths = new Map();
const healsByDepth = new Map();
const lossDetails = [];
const terminalByDepth = new Map();
function rec(map,key){ if("'!map.has(key)) map.set(key,{runsReached:new Set(),hitEvents:0,damage:0,enemyTurns:0,moveEvents:0,waitEvents:0,abilityEvents:0,playerHits:0,playerDamageToEnemies:0,heals:0,healAmount:0}); return map.get(key); }
for (const row of rows) {
  const lines = readFileSync(row.tracePath,'"'utf8').trim().split('\\n').slice(1).map(JSON.parse);
  let depth=1;
  let floorAttackers = new Map();
  let runDamageByDepth = new Map();
  let runHealsByDepth = new Map();
  let deathTurn=null, deathDepth=null, deathAttacker=null, deathAtk=null;
  for (const line of lines) {
    const attackersThisTurn = new Set();
    for (const event of line.events ?? []) {
      if (event.type === 'run_floor_entered') depth = event.data.depth;
      rec(byDepth, depth).runsReached.add(row.policy+':'+row.seed);
      rec(byBand, bandForDepth(depth)).runsReached.add(row.policy+':'+row.seed);
      if (event.type === 'actor_turn' && event.data.actorId.startsWith('enemy#')) { rec(byDepth, depth).enemyTurns++; rec(byBand, bandForDepth(depth)).enemyTurns++; }
      if (event.type === 'enemy_moved') { rec(byDepth, depth).moveEvents++; rec(byBand, bandForDepth(depth)).moveEvents++; }
      if (event.type === 'enemy_waited') { rec(byDepth, depth).waitEvents++; rec(byBand, bandForDepth(depth)).waitEvents++; }
      if (event.type === 'enemy_ability_used') { rec(byDepth, depth).abilityEvents++; rec(byBand, bandForDepth(depth)).abilityEvents++; }
      if (event.type === 'attack_hit') {
        if (event.data.defenderId === 'player') {
          const dmg = event.data.damage;
          const atk = event.data.attackerAttack;
          const drec = rec(byDepth, depth); drec.hitEvents++; drec.damage += dmg;
          const brec = rec(byBand, bandForDepth(depth)); brec.hitEvents++; brec.damage += dmg;
          byAtk.set(atk, (byAtk.get(atk) ?? {hits:0, damage:0, depths:new Map() }));
          const arec = byAtk.get(atk); arec.hits++; arec.damage += dmg; arec.depths.set(depth, (arec.depths.get(depth)??0)+1);
          floorAttackers.set(depth, floorAttackers.get(depth) ?? new Set()); floorAttackers.get(depth).add(event.data.actorId); attackersThisTurn.add(event.data.actorId);
          runDamageByDepth.set(depth, (runDamageByDepth.get(depth)??0)+dmg);
          deathAttacker = event.data.actorId; deathAtk = atk;
        } else if (event.data.actorId === 'player') {
          const drec = rec(byDepth, depth); drec.playerHits++; drec.playerDamageToEnemies += event.data.damage;
          const brec = rec(byBand, bandForDepth(depth)); brec.playerHits++; brec.playerDamageToEnemies += event.data.damage;
        }
      }
      if (event.type === 'effect_executed' && event.data.verb === 'heal' && event.data.targetId === 'player') {
        const amt = event.data.details.hpAfter - event.data.details.hpBefore;
        rec(byDepth, depth).heals++; rec(byDepth, depth).healAmount += amt;
        rec(byBand, bandForDepth(depth)).heals++; rec(byBand, bandForDepth(depth)).healAmount += amt;
        runHealsByDepth.set(depth, (runHealsByDepth.get(depth)??0)+amt);
        healsByDepth.set(depth, (healsByDepth.get(depth)??0)+amt);
      }
      if (event.type === 'entity_died' && event.data.entityId === 'player') { deathTurn = line.turn; deathDepth = depth; }
    }
  }
  terminalByDepth.set(row.depth, terminalByDepth.get(row.depth) ?? {LOSS:0,ABORTED:0,WIN:0});
  terminalByDepth.get(row.depth)[row.terminal] = (terminalByDepth.get(row.depth)[row.terminal]??0)+1;
  if (row.terminal === 'LOSS') {
    deaths.set(row.depth, (deaths.get(row.depth)??0)+1);
    const attackersOnDeathFloor = floorAttackers.get(row.depth)?.size ?? 0;
    lossDetails.push({policy:row.policy,seed:row.seed,depth:row.depth,band:bandForDepth(row.depth),turns:row.turns,kills:row.kills,itemUses:row.itemUses,damageOnDeathFloor:runDamageByDepth.get(row.depth)??0,healOnDeathFloor:runHealsByDepth.get(row.depth)??0,attackersOnDeathFloor,deathAttacker,deathAtk});
  }
}
function printMap(title,map){
  console.log('\\n'+title);
  console.log('key\\treached\\tenemyHits\\tdamage\\tavgDmg/hit\\tplayerHits\\tplayerDmg\\theals\\thealAmt\\tenemyTurns\\tbehaviorEvents');
  for (const [key,v] of [...map.entries()].sort((a,b)=>String(a[0]).localeCompare(String(b[0]), undefined, {numeric:true}))) {
    console.log("'`${key}'"\\t"'${v.runsReached.size}'"\\t"'${v.hitEvents}'"\\t"'${v.damage}'"\\t"'${v.hitEvents? (v.damage/v.hitEvents).toFixed(2):'"'0'}\\t"'${v.playerHits}'"\\t"'${v.playerDamageToEnemies}'"\\t"'${v.heals}'"\\t"'${v.healAmount}'"\\t"'${v.enemyTurns}'"\\t"'${v.moveEvents+v.waitEvents+v.abilityEvents}`);
  }
}
console.log('"'Baseline terminal counts:', rows.reduce((a,r)=>(a[r.terminal]=(a[r.terminal]??0)+1,a),{}));
console.log('Deaths by depth:', Object.fromEntries([...deaths.entries()].sort((a,b)=>a[0]-b[0])));
console.log('Terminals at final depth:', Object.fromEntries([...terminalByDepth.entries()].sort((a,b)=>a[0]-b[0]).map(([k,v])=>[k,v])));
printMap('By band', byBand);
printMap('By depth', byDepth);
console.log('\\nEnemy attack value pressure');
console.log('atk\\thits\\tdamage\\tdepthHits');
for (const [atk,v] of [...byAtk.entries()].sort((a,b)=>a[0]-b[0])) console.log("'`${atk}'"\\t"'${v.hits}'"\\t"'${v.damage}'"\\t"'${[...v.depths.entries()].sort((a,b)=>a[0]-b[0]).map(([d,c])=>`${d}:${c}`).join('"',')}"'`);
console.log('"'\\nLoss attacker profile');
const prof = lossDetails.reduce((a,r)=>{const k=r.attackersOnDeathFloor<=1?'single-attacker-floor':'multi-attacker-floor';a[k]=(a[k]??0)+1; return a;},{}); console.log(prof);
console.table(lossDetails.map(r=>({policy:r.policy,seed:r.seed,depth:r.depth,band:r.band,turns:r.turns,kills:r.kills,itemUses:r.itemUses,damageOnDeathFloor:r.damageOnDeathFloor,healOnDeathFloor:r.healOnDeathFloor,attackersOnDeathFloor:r.attackersOnDeathFloor,deathAtk:r.deathAtk})));
NODE"

