const { rows } = JSON.parse(readFileSync('/tmp/balance-iter3-5.json','utf8'));
const bandForDepth = d => d <= 4 ? 'shallows' : d <= 9 ? 'middle' : 'lowest';
const byDepth = new Map(), byBand=new Map(), deaths=new Map(), byAtk=new Map();
function rec(map,key){ if("'!map.has(key)) map.set(key,{reached:new Set(),hits:0,dmg:0,heals:0,healAmt:0,playerHits:0,playerDmg:0,enemyTurns:0,behavior:0}); return map.get(key); }
const lossDetails=[];
for (const row of rows) {
 let depth=1; const attackers=new Map(), dmgDepth=new Map(), healDepth=new Map(); let deathAtk=null;
 const lines=readFileSync(row.tracePath,'"'utf8').trim().split('\\n').slice(1).map(JSON.parse);
 for (const line of lines) for (const e of line.events??[]) {
  if(e.type==='run_floor_entered') depth=e.data.depth;
  rec(byDepth,depth).reached.add(row.policy+row.seed); rec(byBand,bandForDepth(depth)).reached.add(row.policy+row.seed);
  if(e.type==='actor_turn' && e.data.actorId.startsWith('enemy#')) {rec(byDepth,depth).enemyTurns++; rec(byBand,bandForDepth(depth)).enemyTurns++;}
  if(e.type==='enemy_moved'||e.type==='enemy_waited'||e.type==='enemy_ability_used') {rec(byDepth,depth).behavior++; rec(byBand,bandForDepth(depth)).behavior++;}
  if(e.type==='attack_hit') {
   if(e.data.defenderId==='player') { const d=e.data.damage, atk=e.data.attackerAttack; rec(byDepth,depth).hits++; rec(byDepth,depth).dmg+=d; rec(byBand,bandForDepth(depth)).hits++; rec(byBand,bandForDepth(depth)).dmg+=d; byAtk.set(atk,(byAtk.get(atk)??{hits:0,dmg:0})); byAtk.get(atk).hits++; byAtk.get(atk).dmg+=d; attackers.set(depth, attackers.get(depth)??new Set()); attackers.get(depth).add(e.data.actorId); dmgDepth.set(depth,(dmgDepth.get(depth)??0)+d); deathAtk=atk; }
   if(e.data.actorId==='player') { rec(byDepth,depth).playerHits++; rec(byDepth,depth).playerDmg+=e.data.damage; rec(byBand,bandForDepth(depth)).playerHits++; rec(byBand,bandForDepth(depth)).playerDmg+=e.data.damage; }
  }
  if(e.type==='effect_executed' && e.data.verb==='heal' && e.data.targetId==='player') { const amt=e.data.details.hpAfter-e.data.details.hpBefore; rec(byDepth,depth).heals++; rec(byDepth,depth).healAmt+=amt; rec(byBand,bandForDepth(depth)).heals++; rec(byBand,bandForDepth(depth)).healAmt+=amt; healDepth.set(depth,(healDepth.get(depth)??0)+amt); }
 }
 if(row.terminal==='LOSS') { deaths.set(row.depth,(deaths.get(row.depth)??0)+1); lossDetails.push({policy:row.policy,seed:row.seed,depth:row.depth,band:bandForDepth(row.depth),turns:row.turns,kills:row.kills,itemUses:row.itemUses,dmg:dmgDepth.get(row.depth)??0,heal:healDepth.get(row.depth)??0,attackers:attackers.get(row.depth)?.size??0,deathAtk}); }
}
console.log('counts', rows.reduce((a,r)=>(a[r.terminal]=(a[r.terminal]??0)+1,a),{})); console.log('deaths', Object.fromEntries([...deaths.entries()].sort((a,b)=>a[0]-b[0])));
for (const [title,map] of [['band',byBand],['depth',byDepth]]) { console.log('\\n'+title); console.log('key reached hits dmg avg playerHits playerDmg heals healAmt enemyTurns behavior'); for(const [k,v] of [...map.entries()].sort((a,b)=>String(a[0]).localeCompare(String(b[0]), undefined,{numeric:true}))) console.log(k,v.reached.size,v.hits,v.dmg,v.hits?(v.dmg/v.hits).toFixed(2):0,v.playerHits,v.playerDmg,v.heals,v.healAmt,v.enemyTurns,v.behavior); }
console.log('atk', [...byAtk.entries()].sort((a,b)=>a[0]-b[0])); console.table(lossDetails);
NODE"

