if(row.terminal==='LOSS') loss.push({policy:row.policy,seed:row.seed,depth:row.depth,band:band(row.depth),turns:row.turns,kills:row.kills,itemUses:row.itemUses,dmg:dmgD.get(row.depth)??0,heal:healD.get(row.depth)??0,attackers:atkers.get(row.depth)?.size??0,deathAtk});}
console.log(rows.reduce((a,r)=>(a[r.terminal]=(a[r.terminal]??0)+1,a),{}));
for(const [title,m] of [['band',byBand],['depth',byDepth]]){console.log('\\n'+title); for(const [k,v] of [...m.entries()].sort((a,b)=>String(a[0]).localeCompare(String(b[0]),undefined,{numeric:true}))) console.log(k,'reached',v.reached.size,'hits',v.hits,'dmg',v.dmg,'avg',v.hits?(v.dmg/v.hits).toFixed(1):0,'playerDmg',v.playerDmg,'heals',v.heals,'healAmt',v.healAmt);}
console.table(loss);
NODE"

